import{_ as o,o as a,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"132. On Call Rostered Overtime","description":"","frontmatter":{"title":"132. On Call Rostered Overtime","eba":"Mental Health Services 2024-2028","topics":["leave","annual-leave","hours","overtime"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/132-on-call-rostered-overtime.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/132-on-call-rostered-overtime.md"}'),l={name:"ebas/mental-health/health-professionals/hours-of-work/132-on-call-rostered-overtime.md"};function s(n,e,i,d,m,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_132-on-call-rostered-overtime" tabindex="-1">132. On Call Rostered Overtime <a class="header-anchor" href="#_132-on-call-rostered-overtime" aria-label="Permalink to &quot;132. On Call Rostered Overtime&quot;">​</a></h1><p><strong>132.1</strong> An Employee who is rostered on-call or who performs rostered overtime on 10 or more weekends per annum will be entitled to an additional five days annual leave. This entitlement is in addition to the shift worker entitlement provided by clause 38D.2, but both entitlements cannot be claimed for the same bodies of work.</p><p><strong>132.2</strong> Clause 132.1 above does not apply to any weekend on which four hours or less is worked or on-call.</p><p><strong>132.3</strong> Leave loading does not apply to leave accrued under clause 132.1 above.</p><p><strong>132.4</strong> A part-time Employee paid in accordance with <a href="/eba/ebas/mental-health/common-terms/employment-types/25-modes-of-employment.html">clause 25.2</a> will accrue paid leave entitlements under <a href="/eba/ebas/mental-health/health-professionals/hours-of-work/122-hours-of-work.html">clause 122.1</a> on a pro-rata basis.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',6)])])}const u=o(l,[["render",s]]);export{c as __pageData,u as default};
